package main

import (
	"bytes"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	args := pingArgs(host, count)
	cmd := exec.Command("ping", args...)

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	output := stdout.String()
	if output == "" {
		output = stderr.String()
	} else if stderr.Len() > 0 {
		output += "\n" + stderr.String()
	}

	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w; output: %s", err, strings.TrimSpace(output))
	}

	avg, parseErr := parseAverageLatency(output)
	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w; output: %s", parseErr, strings.TrimSpace(output))
	}

	return avg, nil
}

func pingArgs(host string, count int) []string {
	if runtime.GOOS == "windows" {
		return []string{"-n", strconv.Itoa(count), host}
	}
	return []string{"-c", strconv.Itoa(count), host}
}

func parseAverageLatency(output string) (float64, error) {
	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)(?:round-trip|rtt)[^=]*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`),
		regexp.MustCompile(`(?m)Average\s*=\s*(\d+(?:\.\d+)?)ms`),
		regexp.MustCompile(`(?m)avg(?:/|=)([\d.]+)`),
	}

	for _, re := range patterns {
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 2 {
			v, err := strconv.ParseFloat(matches[1], 64)
			if err == nil {
				return v, nil
			}
		}
	}

	return 0, errors.New("average latency not found")
}

func main() {
	host := "8.8.8.8"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		parsedCount, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "invalid count: %v\n", err)
			os.Exit(1)
		}
		count = parsedCount
	}

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d ping(s): %.2f ms\n", host, count, latency)
}

