package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
//
// It uses the system "ping" command via os/exec and parses the output to extract
// the average round-trip time.
//
// Supported output formats include common Linux and macOS variants, such as:
//   - rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
//   - round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
func MeasureLatency(host string, count int) (float64, error) {
	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Use exec.Command directly instead of invoking through a shell to avoid
	// shell injection issues and quoting problems.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	outputStr := string(output)

	// Match both Linux and macOS summary lines and capture the avg value.
	// Examples:
	//   rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	//   round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", outputStr)
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	avg, err := MeasureLatency("127.0.0.1", 3)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Printf("Average latency: %.3f ms\n", avg)
}

