func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w; output: %s", err, strings.TrimSpace(string(output)))
	}

	avg, err := parseAverageLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w; output: %s", err, strings.TrimSpace(string(output)))
	}

	return avg, nil
}

func parseAverageLatency(output string) (float64, error) {
	patterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`),
		regexp.MustCompile(`(?m)=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+`),
		regexp.MustCompile(`(?mi)average\s*=\s*([\d.]+)\s*ms`),
	}

	for _, re := range patterns {
		matches := re.FindStringSubmatch(output)
		if len(matches) >= 2 {
			value, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, err
			}
			return value, nil
		}
	}

	return 0, errors.New("average latency not found")
}

func main() {
	host := "8.8.8.8"
	count := 4

	if len(os.Args) > 1 {
		host = os.Args[1]
	}
	if len(os.Args) > 2 {
		parsedCount, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "invalid count: %v\n", err)
			os.Exit(1)
		}
		count = parsedCount
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d ping(s): %.2f ms\n", host, count, avg)
}

