package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// hostPattern allows common hostname, IPv4, and simple IPv6 formats.
// This validation helps prevent argument abuse while still allowing typical ping targets.
var hostPattern = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9.\-:]{0,252}[a-zA-Z0-9]$`)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
//
// Security fixes:
// - Avoids shell execution ("bash -c") to prevent command injection.
// - Validates host input.
// - Validates count range.
// - Passes arguments directly to exec.Command.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if len(host) > 254 || !hostPattern.MatchString(host) {
		return 0, errors.New("invalid host")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 20 {
		return 0, errors.New("count exceeds maximum allowed value")
	}

	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "rtt min/avg/max") || strings.Contains(line, "round-trip min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Supports common Linux/macOS ping summary formats:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`=\s*\d+(?:\.\d+)?/(\d+(?:\.\d+)?)/\d+(?:\.\d+)?/\d+(?:\.\d+)?\s*ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	avg, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Printf("Average latency: %.3f ms\n", avg)
}

