package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
//
// It uses the system "ping" command via os/exec and parses the output to extract
// the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Avoid shell invocation to prevent command injection and quoting issues.
	// This implementation targets the common Unix-style ping syntax: ping -c <count> <host>.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, strings.TrimSpace(string(output)))
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	var statsLine string
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Supports common formats such as:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, fmt.Errorf("failed to parse average latency from ping output: %s", statsLine)
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage:
	avg, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Printf("Average latency: %.3f ms\n", avg)
}

