func parseAverageLatency(output string) (float64, error) {
	// Unix-like ping summary:
	// rtt min/avg/max/mdev = 10.123/20.456/30.789/1.234 ms
	unixRe := regexp.MustCompile(`(?m)(?:rtt|round-trip)[^=]*=\s*([\d.]+)/([\d.]+)/([\d.]+)(?:/[\d.]+)?\s*ms`)
	if matches := unixRe.FindStringSubmatch(output); len(matches) >= 3 {
		return strconv.ParseFloat(matches[2], 64)
	}

	// Windows ping summary:
	// Minimum = 10ms, Maximum = 20ms, Average = 15ms
	winRe := regexp.MustCompile(`(?i)Average\s*=\s*(\d+)(?:ms)?`)
	if matches := winRe.FindStringSubmatch(output); len(matches) >= 2 {
		return strconv.ParseFloat(matches[1], 64)
	}

	return 0, errors.New("average latency not found")
}

