// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
//
// It uses the system "ping" command via os/exec and parses the output to extract
// the average RTT.
//
// Supported output formats include common Linux/macOS variants such as:
//   - rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
//   - round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
func MeasureLatency(host string, count int) (float64, error) {
	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	if isWindows() {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	avg, err := parseAverageLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avg, nil
}

func isWindows() bool {
	return strings.EqualFold(runtimeGOOS(), "windows")
}

func runtimeGOOS() string {
	return runtime.GOOS
}

func parseAverageLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Unix-like ping summary:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	unixRe := regexp.MustCompile(`(?:rtt|round-trip)[^=]*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`)
	for _, line := range lines {
		if matches := unixRe.FindStringSubmatch(line); len(matches) == 2 {
			return strconv.ParseFloat(matches[1], 64)
		}
	}

	// Windows ping summary:
	// Minimum = 10ms, Maximum = 20ms, Average = 15ms
	winRe := regexp.MustCompile(`Average = (\d+)ms`)
	for _, line := range lines {
		if matches := winRe.FindStringSubmatch(line); len(matches) == 2 {
			return strconv.ParseFloat(matches[1], 64)
		}
	}

	return 0, errors.New("could not find average latency in ping output")
}

func main() {
	avg, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Printf("Average latency: %.3f ms\n", avg)
}

