// hostnameRegex allows common DNS hostnames, localhost, and IPv4 addresses.
// This validation helps prevent command/argument abuse while still allowing
// typical ping targets.
var hostnameRegex = regexp.MustCompile(`^(?i:[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?(?:\.[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?)*|localhost|\d{1,3}(?:\.\d{1,3}){3})$`)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds. It uses the system "ping" command via
// os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 20 {
		return 0, errors.New("count must not exceed 20")
	}
	if !isValidHost(host) {
		return 0, errors.New("invalid host")
	}

