	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	avg, err := parseAverageLatency(string(output))
	if err != nil {
		return 0, err
	}

	return avg, nil
}

func isValidHost(host string) bool {
	if len(host) > 253 {
		return false
	}
	if !hostnameRegex.MatchString(host) {
