package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
//
// It uses the system "ping" command via os/exec and parses the output to extract
// the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if strings.TrimSpace(host) == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	avg, err := parseAverageLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avg, nil
}

func parseAverageLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Unix-like systems:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	unixRe := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = [\d.]+/([\d.]+)/[\d.]+/[\d.]+ ms`)

	// Windows:
	// Minimum = 10ms, Maximum = 14ms, Average = 12ms
	windowsRe := regexp.MustCompile(`(?i)average\s*=\s*(\d+)\s*ms`)

	for _, line := range lines {
		line = strings.TrimSpace(line)

		if matches := unixRe.FindStringSubmatch(line); len(matches) == 2 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("invalid unix average latency value: %w", err)
			}
			return avg, nil
		}

		if matches := windowsRe.FindStringSubmatch(line); len(matches) == 2 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("invalid windows average latency value: %w", err)
			}
			return avg, nil
		}
	}

	return 0, errors.New("could not find average latency in ping output")
}

func main() {
	// Example usage
	avg, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", avg)
}

