package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host count times and returns the average
// latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w; output: %s", err, strings.TrimSpace(string(output)))
	}

	avg, err := parseAverageLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w", err)
	}

	return avg, nil
}

func parseAverageLatency(output string) (float64, error) {
	// Unix-like output example:
	// rtt min/avg/max/mdev = 14.123/15.456/16.789/0.321 ms
	unixPatterns := []*regexp.Regexp{
		regexp.MustCompile(`(?m)(?:rtt|round-trip)[^=]*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`),
		regexp.MustCompile(`(?m)(?:rtt|round-trip)[^=]*=\s*[\d.]+/([\d.]+)/[\d.]+\s*ms`),
	}

	for _, re := range unixPatterns {
		matches := re.FindStringSubmatch(output)
		if len(matches) == 2 {
			avg, err := strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, err
			}
			return avg, nil
		}
	}

	// Windows output example:
	// Minimum = 10ms, Maximum = 20ms, Average = 15ms
	// Some locales/versions may include spaces: Average = 15ms
	windowsPattern := regexp.MustCompile(`(?i)average\s*=\s*(\d+)(?:ms)?`)
	matches := windowsPattern.FindStringSubmatch(output)
	if len(matches) == 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, err
		}
		return avg, nil
	}

	return 0, errors.New("average latency not found in ping output")
}

func main() {
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Printf("Average latency to %s over %d ping(s): %.2f ms\n", host, count, avg)
}

