package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns
// the average latency in milliseconds.
//
// It uses the system "ping" command via os/exec and parses the command output.
// The function supports common ping output formats on Unix-like systems and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	avg, parseErr := parseAverageLatency(string(output))
	if parseErr != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w (output: %s)", parseErr, string(output))
	}

	return avg, nil
}

func parseAverageLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")

	// Unix-like examples:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	unixRe := regexp.MustCompile(`(?:rtt|round-trip)[^=]*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`)

	for _, line := range lines {
		line = strings.TrimSpace(line)
		if match := unixRe.FindStringSubmatch(line); len(match) == 2 {
			avg, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				return 0, fmt.Errorf("invalid unix average latency value: %w", err)
			}
			return avg, nil
		}
	}

	// Windows example:
	// Minimum = 10ms, Maximum = 30ms, Average = 20ms
	windowsRe := regexp.MustCompile(`(?i)average\s*=\s*(\d+)(?:ms)?`)
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if match := windowsRe.FindStringSubmatch(line); len(match) == 2 {
			avg, err := strconv.ParseFloat(match[1], 64)
			if err != nil {
				return 0, fmt.Errorf("invalid windows average latency value: %w", err)
			}
			return avg, nil
		}
	}

	return 0, errors.New("could not find average latency in ping output")
}

func main() {
	// Example usage:
	avg, err := MeasureLatency("127.0.0.1", 4)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Printf("Average latency: %.2f ms\n", avg)
}

