import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host count times and returns the average
// latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w; output: %s", err, strings.TrimSpace(string(output)))
	}

	avg, err := parseAverageLatency(string(output))
	if err != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w; output: %s", err, strings.TrimSpace(string(output)))
	}

	return avg, nil
}

func parseAverageLatency(output string) (float64, error) {
	// Linux/macOS style:
	// rtt min/avg/max/mdev = 14.123/15.456/16.789/0.321 ms
	// round-trip min/avg/max/stddev = 14.123/15.456/16.789/0.321 ms
	unixPattern := regexp.MustCompile(`(?:rtt|round-trip)[^=]*=\s*([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)\s*ms`)
	if matches := unixPattern.FindStringSubmatch(output); len(matches) >= 3 {
		avg, err := strconv.ParseFloat(matches[2], 64)
		if err != nil {
			return 0, err
		}
		return avg, nil
	}

	// Windows style:
	// Minimum = 10ms, Maximum = 20ms, Average = 15ms
	windowsPattern := regexp.MustCompile(`Average = ([0-9]+)ms`)
	if matches := windowsPattern.FindStringSubmatch(output); len(matches) >= 2 {
		avg, err := strconv.ParseFloat(matches[1], 64)
		if err != nil {
			return 0, err
		}
		return avg, nil
	}

	return 0, errors.New("average latency not found")
}

func main() {
	host := "8.8.8.8"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Println("Error:", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

