	// while still supporting common hostnames, IPv4, and simple IPv6 literals.
	hostPattern := regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9.\-:]{0,252}[a-zA-Z0-9]$|^[a-zA-Z0-9]$`)
	if !hostPattern.MatchString(host) {
		return 0, errors.New("host contains invalid characters")
	}
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("host must not start with '-'")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w", err)
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		line = strings.TrimSpace(line)
		if strings.Contains(line, "min/avg/max") ||
			strings.Contains(line, "round-trip min/avg/max") ||
			strings.Contains(line, "Minimum =") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find latency statistics in ping output")
	}

	// Unix-like example:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	unixRe := regexp.MustCompile(`(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*\d+(?:\.\d+)?/(\d+(?:\.\d+)?)/\d+(?:\.\d+)?/\d+(?:\.\d+)?\s*ms`)
	if matches := unixRe.FindStringSubmatch(statsLine); len(matches) == 2 {
		avg, parseErr := strconv.ParseFloat(matches[1], 64)
		if parseErr != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", parseErr)
		}
		return avg, nil
	}

	// Windows example:
	// Minimum = 10ms, Maximum = 30ms, Average = 20ms
	windowsRe := regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)ms`)
	if matches := windowsRe.FindStringSubmatch(statsLine); len(matches) == 2 {
		avg, parseErr := strconv.ParseFloat(matches[1], 64)
		if parseErr != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", parseErr)
		}
		return avg, nil
	}

